```typescript
// src/utils/logger.ts
export const colors = {
  reset: '\x1b[0m',
  bright: '\x1b[1m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
};

export class AgentLogger {
  private agentName: string;

  constructor(agentName: string) {
    this.agentName = agentName;
  }

  info(message: string) {
    console.log(`${colors.blue}[INFO]${colors.reset} [${this.agentName}] ${message}`);
  }

  success(message: string) {
    console.log(`${colors.green}[✓]${colors.reset} [${this.agentName}] ${message}`);
  }

  error(message: string) {
    console.log(`${colors.red}[✗]${colors.reset} [${this.agentName}] ${message}`);
  }
}
```

